package com.nattechnologies.trastcms.plugins.saas; import jakarta.persistence.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="saas_product") class SaasProduct{@Id@Column(length=36)String id;@Column(name="product_key",nullable=false,unique=true,length=100)String productKey;@Column(nullable=false,length=200)String name;@Lob String description;@Column(name="logo_url",length=1000)String logoUrl;@Column(nullable=false)boolean active=true;@Column(name="created_at",nullable=false)Instant createdAt;@PrePersist void create(){if(id==null)id=UUID.randomUUID().toString();createdAt=Instant.now();}}
